        for sid in ["sum-acct", "sum-other"] {
            tx.execute(
                "INSERT INTO mem_tree_summary_embeddings (
                    summary_id, model_signature, vector, dim, created_at
                ) VALUES (?1, 'test/model@3', ?2, 3, 1700000000.0)",
                params![sid, vec![1_u8, 2, 3]],
            )?;
        }
