        tree_store::upsert_buffer_tx(
            &tx,
            &Buffer {
                tree_id: "tree-other".into(),
                level: 0,
                item_ids: vec![b0.id.clone()],
                token_sum: 12,
                oldest_at: Some(ts),
            },
        )?;

        assert!(claim_source_ingest_tx(
            &tx,
            SourceKind::Email,
            "gmail:acct",
            1_700_000_000_000
        )?);
        assert!(claim_source_ingest_tx(
            &tx,
            SourceKind::Email,
            "gmail:other",
            1_700_000_000_000
        )?);
        tx.commit()?;
        Ok(())
    }).unwrap

